CREATE TABLE categories (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT NOT NULL UNIQUE); CREATE TABLE staff (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, fullName TEXT NOT NULL, firstName TEXT NOT NULL, login TEXT NOT NULL UNIQUE); CREATE TABLE products (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT NOT NULL, price DECIMAL(10,2) NOT NULL, category TEXT NOT NULL, desc TEXT, images JSONB DEFAULT '[]'::jsonb, code TEXT, stock BOOLEAN DEFAULT TRUE, createdAt TIMESTAMPTZ DEFAULT NOW()); INSERT INTO categories (name) VALUES ('Utilidades'), ('Presentes'), ('Eletrônicos'), ('Cozinha');